<?php
namespace Tests\Feature\Accounting;
use App\Domain\Accounting\Actions\PostJournal;use App\Domain\Accounting\Actions\ProvisionAccounting;use App\Domain\Accounting\Actions\ReverseJournal;use App\Enums\JournalStatus;use App\Models\Cooperative;use App\Models\LedgerAccount;use App\Support\Tenancy\TenantContext;use Illuminate\Foundation\Testing\RefreshDatabase;use Illuminate\Validation\ValidationException;use LogicException;use Tests\TestCase;
class JournalIntegrityTest extends TestCase{use RefreshDatabase;private function provision():void{$cooperative=Cooperative::factory()->create();app(TenantContext::class)->set($cooperative);app(ProvisionAccounting::class)->execute();}public function test_unbalanced_journal_is_rejected():void{$this->provision();$cash=LedgerAccount::query()->where('code','1000')->firstOrFail();try{app(PostJournal::class)->execute(['entry_date'=>today()->toDateString(),'description'=>'Invalid','lines'=>[['ledger_account_id'=>$cash->id,'debit_minor'=>1000,'credit_minor'=>0],['ledger_account_id'=>$cash->id,'debit_minor'=>0,'credit_minor'=>999]]]);$this->fail('Unbalanced journal should fail.');}catch(ValidationException){$this->assertDatabaseCount('journal_entries',0);}}public function test_posted_lines_are_immutable_and_reversal_swaps_sides():void{$this->provision();$cash=LedgerAccount::query()->where('code','1000')->firstOrFail();$contributions=LedgerAccount::query()->where('code','2100')->firstOrFail();$entry=app(PostJournal::class)->execute(['entry_date'=>today()->toDateString(),'description'=>'Contribution','lines'=>[['ledger_account_id'=>$cash->id,'debit_minor'=>5000,'credit_minor'=>0],['ledger_account_id'=>$contributions->id,'debit_minor'=>0,'credit_minor'=>5000]]]);try{$entry->lines->first()->update(['debit_minor'=>4000]);$this->fail('Journal line should be immutable.');}catch(LogicException){}$reversal=app(ReverseJournal::class)->execute($entry,'Entry error',today()->toDateString());$this->assertSame(JournalStatus::Reversed,$entry->refresh()->status);$this->assertSame(5000,$reversal->lines->first()->credit_minor);}}
